/**
 * Specialist: Hardcoded Secrets Detection
 * Scans source files for potential hardcoded secrets: API keys, tokens,
 * passwords, private keys, database URLs with credentials.
 */

export const checkId = 'secrets';
export const name = 'No Hardcoded Secrets';
export const appliesTo = ['all'];

// ── Patterns ───────────────────────────────────────────────────────────

const SECRET_PATTERNS = [
  { regex: /\b(sk-[a-zA-Z0-9]{20,})/, name: 'API key (sk- prefix)' },
  { regex: /\b(pk_[a-zA-Z0-9_]{20,})/, name: 'API key (pk_ prefix)' },
  { regex: /\b(ghp_[a-zA-Z0-9]{36})/, name: 'GitHub token' },
  { regex: /\b(gho_[a-zA-Z0-9]{36})/, name: 'GitHub OAuth token' },
  { regex: /\b(AIza[0-9A-Za-z_\-]{35})/, name: 'Google API key' },
  { regex: /\b(Bearer\s+[a-zA-Z0-9_\-\.]{20,})/, name: 'Bearer token' },
  { regex: /-----BEGIN (RSA |EC |DSA |OPENSSH )?PRIVATE KEY-----/, name: 'Private key', captureGroup: -1 },
  { regex: /((?:mongodb|postgres|mysql|redis):\/\/[^:]+:[^@]+@)/, name: 'DB URL with password', captureGroup: 1 },
  { regex: /(?:password|passwd|pwd|secret|token|api[_-]?key)\s*[=:]\s*["\']([a-zA-Z0-9]{16,})["\']/i, name: 'Hardcoded credential', captureGroup: 1 },
];

const SAFE_PATTERNS = [
  /localhost/i,
  /127\.0\.0\.1/,
  /example\.com/i,
  /\btest_/i,
  /dummy/i,
  /placeholder/i,
  /changeme/i,
  /YOUR_/i,
  /XXXX/i,
  /REDACTED/i,
  /process\.env\./,
  /import\.meta\.env\./,
  /Deno\.env/,
  /Bun\.env/,
];

const SKIP_PATHS = [
  /test/i, /spec/i, /__tests__/, /examples?/, /fixtures/, /docs?/,
  /\.md$/, /\.test\./, /\.spec\./, /\.d\.ts$/, /\.lock$/, /\.env\./, /\.env$/, /mock/i, /snapshot/,
];

const VENDOR_PATHS = [
  /(?:^|\/)node_modules\//,
  /(?:^|\/)\.yarn\//,
  /(?:^|\/)\.pnpm\//,
  /(?:^|\/)vendor\//,
  /(?:^|\/)third_party\//,
  /(?:^|\/)dist\//,
  /(?:^|\/)build\//,
  /(?:^|\/)\.next\//,
  /(?:^|\/)\.nuxt\//,
  /(?:^|\/)out\//,
  /(?:^|\/)coverage\//,
  /(?:^|\/)\_next\//,
  /(?:^|\/)\.turbo\//,
  /(?:^|\/)\.parcel-cache\//,
  /(?:^|\/)\.webpack\//,
  /(?:^|\/)\.cache\//,
  /(?:^|\/)\.output\//,
  /(?:^|\/)\.vercel\//,
  /(?:^|\/)\.netlify\//,
];

const SCANNABLE_EXTS = /\.(js|ts|jsx|tsx|mjs|cjs|py|rb|go|java|kt|rs)$/;

const STRONG_SECRET_RE = /(?:\b|_)(api[_-]?key|secret[_-]?key|private[_-]?key|auth[_-]?token|access[_-]?token|refresh[_-]?token|password|passwd|pwd|api[_-]?secret|db[_-]?password|app[_-]?secret|client[_-]?secret|secret[_-]?token|auth[_-]?key|credentials)(?:\b|_)\s*[:=](?!=)/i;

const MEDIUM_SECRET_RE = /(?:\b|_)(secret|token|key|auth|credential)(?:\b|_)\s*[:=](?!=)/i;

const PREFIX_FRAGMENTS = ['AKIA', 'ASIA', 'ghp_', 'gho_', 'ghs_', 'ghu_', 'ghr_', 'AIza', 'npm_', 'xoxb-', 'xoxp-', 'xoxa-', 'xoxr-', 'xoxs-', 'sk_live_', 'pk_live_', 'sk_test_', 'pk_test_', 'sk-test-', 'pk-test-', 'bearer '];

// ── Helpers ────────────────────────────────────────────────────────────

function shouldScanFile(path) {
  if (!SCANNABLE_EXTS.test(path)) return false;
  if (SKIP_PATHS.some((p) => p.test(path))) return false;
  if (VENDOR_PATHS.some((p) => p.test(path))) return false;
  return true;
}

function isSafeLine(line) {
  return SAFE_PATTERNS.some((p) => p.test(line));
}

function isCommentLine(line) {
  const trimmed = line.trim();
  return (
    trimmed.startsWith('//') ||
    trimmed.startsWith('*') ||
    trimmed.startsWith('#')
  );
}

function getEntropy(str) {
  const len = str.length;
  if (len === 0) return 0;
  const freq = {};
  for (const ch of str) freq[ch] = (freq[ch] || 0) + 1;
  let entropy = 0;
  for (const ch in freq) {
    const p = freq[ch] / len;
    entropy -= p * Math.log2(p);
  }
  return entropy;
}

function extractQuotedStrings(line) {
  const strings = [];
  const re = /(['"])(.*?)\1/g;
  let m;
  while ((m = re.exec(line)) !== null) {
    strings.push(m[2]);
  }
  return strings;
}

function getCodeBeforeStrings(line) {
  const idx = line.search(/['"]/);
  return idx >= 0 ? line.slice(0, idx) : line;
}

function hasStrongSecretContext(line) {
  const code = getCodeBeforeStrings(line);
  return STRONG_SECRET_RE.test(code);
}

function hasMediumSecretContext(line) {
  const code = getCodeBeforeStrings(line);
  return MEDIUM_SECRET_RE.test(code);
}

function hasAnySecretContext(line) {
  return hasStrongSecretContext(line) || hasMediumSecretContext(line);
}

function isSecretFilePath(path) {
  return /(?:^|\/)(env|config|secret|credential|key|auth|token|password)/i.test(path);
}

function hasPrefixFragment(strs) {
  const combined = strs.join('');
  for (const p of PREFIX_FRAGMENTS) {
    const pl = p.toLowerCase();
    if (combined.toLowerCase().startsWith(pl)) return p;
    for (const s of strs) {
      if (s.toLowerCase().startsWith(pl)) return p;
    }
  }
  return null;
}

function looksLikeRandomToken(str) {
  const isHex = /^[a-f0-9]+$/i.test(str);
  const isBase64 = /^[A-Za-z0-9+/=]+$/.test(str) && str.length >= 8;
  const highEntropy = getEntropy(str) > 4.0;
  const hasMixed = /[a-z]/.test(str) && /[A-Z]/.test(str) && /[0-9]/.test(str);
  return isHex || isBase64 || (highEntropy && hasMixed);
}

function isPathOrUrl(combined) {
  return /https?:\/\//.test(combined) || /^\//.test(combined);
}

function evaluateSplitSecret(strings, contextCode, filePath) {
  if (strings.length < 2) return null;
  const combined = strings.join('');
  if (combined.includes(' ')) return null;
  if (isPathOrUrl(combined)) return null;
  if (combined.length < 8) return null;

  const prefix = hasPrefixFragment(strings);
  if (prefix) return `Potential split hardcoded secret (${prefix})`;

  const strongCtx = hasStrongSecretContext(contextCode);
  const mediumCtx = hasMediumSecretContext(contextCode);
  const isCfg = isSecretFilePath(filePath);

  const shortCount = strings.filter(s => s.length <= 4).length;

  if (strings.length >= 3 && shortCount >= strings.length - 1) {
    if (strongCtx || mediumCtx || isCfg) {
      return 'Potential split hardcoded secret';
    }
  }

  if (strongCtx) {
    if (combined.length >= 12) return 'Potential split hardcoded secret';
    if (looksLikeRandomToken(combined)) return 'Potential split hardcoded secret';
  }

  if ((mediumCtx || isCfg) && strings.length >= 3 && combined.length >= 10) {
    return 'Potential split hardcoded secret';
  }

  return null;
}

function checkSplitSecret(line, filePath) {
  if (!/['"]\s*\+\s*['"]/.test(line)) return null;
  return evaluateSplitSecret(extractQuotedStrings(line), line, filePath);
}

function checkArrayJoinSecret(line, filePath) {
  if (!/\.\s*join\s*\(/.test(line)) return null;
  return evaluateSplitSecret(extractQuotedStrings(line), line, filePath);
}

function checkTemplateLiteralSplit(line, filePath) {
  const strings = [];
  const re = /\$\{['"]([^'"]+)['"]\}/g;
  let m;
  while ((m = re.exec(line)) !== null) {
    strings.push(m[1]);
  }
  if (strings.length < 2) return null;
  return evaluateSplitSecret(strings, line, filePath);
}

function checkMultiLineSplit(lines, startIdx, filePath) {
  const startLine = lines[startIdx];
  if (!hasAnySecretContext(startLine)) return null;

  const startStrings = extractQuotedStrings(startLine);
  const startTrim = startLine.trimEnd();
  const startContinues = /[=:]\s*$/.test(startTrim) || /['"]\s*\+\s*$/.test(startTrim) || /\+\s*$/.test(startTrim);

  if (startStrings.length === 0 && !startContinues) return null;

  let strings = [...startStrings];
  let i = startIdx + 1;
  const maxLines = Math.min(lines.length, startIdx + 8);

  while (i < maxLines) {
    const line = lines[i];
    const trimmed = line.trim();
    if (trimmed === '' || trimmed.startsWith('//')) {
      i++;
      continue;
    }

    strings.push(...extractQuotedStrings(line));

    const endsWithPlus = /['"]\s*\+\s*$/.test(line) || /\+\s*$/.test(trimmed);
    if (!endsWithPlus) {
      let lookAhead = i + 1;
      let foundPlus = false;
      while (lookAhead < maxLines) {
        const tl = lines[lookAhead].trim();
        if (tl === '' || tl.startsWith('//')) {
          lookAhead++;
          continue;
        }
        if (/^\s*\+/.test(lines[lookAhead])) {
          foundPlus = true;
        }
        break;
      }
      if (!foundPlus) break;
    }
    i++;
  }

  if (strings.length < 2) return null;

  const combined = strings.join('');
  if (combined.includes(' ') || isPathOrUrl(combined) || combined.length < 8) return null;

  const prefix = hasPrefixFragment(strings);
  if (prefix) {
    return { issue: `Potential split hardcoded secret (${prefix})`, endIdx: i };
  }

  const contextCode = lines.slice(startIdx, i + 1).join('\n');
  const issue = evaluateSplitSecret(strings, contextCode, filePath);
  if (issue) {
    return { issue, endIdx: i };
  }

  return null;
}

// ── Main Check ─────────────────────────────────────────────────────────

export async function check(context) {
  const { tree, files } = context;

  try {
    const sourceFiles = tree.filter(shouldScanFile).slice(0, 30);
    if (sourceFiles.length === 0) {
      const isEmptyRepo = tree.length === 0;
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: isEmptyRepo ? 'Repo is empty — nothing to scan' : `No scannable source files in ${tree.length} file(s)`,
        findings: [],
      };
    }

    const findings = [];

    for (const filePath of sourceFiles) {
      const content = await files.get(filePath);
      if (!content) continue;

      const lines = content.split('\n');
      let skipToLine = -1;

      for (let i = 0; i < lines.length; i++) {
        if (i <= skipToLine) continue;

        const line = lines[i];

        if (isSafeLine(line)) continue;
        if (isCommentLine(line)) continue;

        let found = false;

        for (const pattern of SECRET_PATTERNS) {
          const match = line.match(pattern.regex);
          if (match) {
            const cg = pattern.captureGroup ?? 1;
            let shouldFlag;
            if (cg === -1) {
              shouldFlag = true;
            } else {
              const candidate = match[cg] || match[0];
              shouldFlag = candidate.length > 8 && getEntropy(candidate) > 3.5;
            }

            if (shouldFlag) {
              findings.push({
                file: filePath,
                line: i + 1,
                issue: `Potential ${pattern.name}`,
              });
              found = true;
            }
            break;
          }
        }

        if (!found) {
          const splitIssue = checkSplitSecret(line, filePath);
          if (splitIssue) {
            findings.push({
              file: filePath,
              line: i + 1,
              issue: splitIssue,
            });
            found = true;
          }
        }

        if (!found) {
          const joinIssue = checkArrayJoinSecret(line, filePath);
          if (joinIssue) {
            findings.push({
              file: filePath,
              line: i + 1,
              issue: joinIssue,
            });
            found = true;
          }
        }

        if (!found) {
          const templateIssue = checkTemplateLiteralSplit(line, filePath);
          if (templateIssue) {
            findings.push({
              file: filePath,
              line: i + 1,
              issue: templateIssue,
            });
            found = true;
          }
        }

        if (!found) {
          const multiLine = checkMultiLineSplit(lines, i, filePath);
          if (multiLine) {
            findings.push({
              file: filePath,
              line: i + 1,
              issue: multiLine.issue,
            });
            skipToLine = multiLine.endIdx;
          }
        }
      }
    }

    if (findings.length === 0) {
      return {
        checkId,
        status: 'pass',
        confidence: 'medium',
        message: `No secrets detected in ${sourceFiles.length} scanned file(s)`,
        findings: [],
      };
    }

    return {
      checkId,
      status: 'fail',
      confidence: 'high',
      message: `${findings.length} potential secret(s) found in ${sourceFiles.length} scanned file(s)`,
      findings,
    };
  } catch (err) {
    console.error(err);
    return {
      checkId,
      status: 'check-it',
      confidence: 'low',
      message: `Error during scan: ${err.message}`,
      findings: [],
    };
  }
}
